INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24001, "アヤネ", 2, 2, 0.0, 401, 102301, "2020/07/31 12:00:00", 24, 0.0, 0.0, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24002, "アヤネ", 1, 2, 0.0, 402, 102301, "2020/07/31 12:00:00", 24, 2.21, 0.0, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24003, "アヤネ", 2, 2, 0.0, 403, 102301, "2020/07/31 12:00:00", 24, 0.0, 0.0, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24004, "アサヒ", 2, 1, 0.0, 701, 192201, "2020/07/31 12:00:00", 24, 1.99, 0.0, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24005, "アサヒ", 1, 2, 0.0, 702, 192201, "2020/07/31 12:00:00", 24, 2.21, 0.0, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24006, "アサヒ", 2, 1, 0.0, 703, 192201, "2020/07/31 12:00:00", 24, 3.33, 0.0, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24007, "部員３", 2, 2, 0.0, 801, 192301, "2020/07/31 12:00:00", 24, 0.0, 0.0, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24008, "部員３", 1, 2, 0.0, 802, 192301, "2020/07/31 12:00:00", 24, 2.68, 0.0, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24009, "部員３", 2, 2, 0.0, 803, 192301, "2020/07/31 12:00:00", 24, 0.0, 0.0, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24010, "", 1, 1, 0.0, 501, 192501, "2020/07/31 12:00:00", 24, 0.0, 0.0, "やった！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24011, "", 1, 1, 0.0, 502, 192501, "2020/07/31 12:00:00", 24, 0.0, 0.0, "勝ったよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24012, "", 1, 1, 0.0, 503, 192501, "2020/07/31 12:00:00", 24, 0.0, 0.0, "いい調子！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24013, "ミサト", 6, 2, 0.0, 111, 113501, "2020/07/31 12:00:00", 24, 5.33, 0.0, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24014, "ミサト", 1, 2, 0.0, 112, 113501, "2020/07/31 12:00:00", 24, 6.85, 0.0, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24015, "ミサト", 1, 2, 0.0, 113, 113501, "2020/07/31 12:00:00", 24, 3.0, 0.0, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24016, "ダイチ", 1, 2, 0.0, 611, 192401, "2020/07/31 12:00:00", 24, 6.11, 0.0, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24017, "ダイチ", 1, 2, 0.0, 612, 192401, "2020/07/31 12:00:00", 24, 6.75, 0.0, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24018, "ダイチ", 2, 2, 0.0, 613, 192401, "2020/07/31 12:00:00", 24, 0.0, 0.0, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24019, "ハツネ", 2, 1, 0.0, 211, 113401, "2020/07/31 12:00:00", 24, 4.52, 0.0, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24020, "ハツネ", 2, 1, 0.0, 212, 113401, "2020/07/31 12:00:00", 24, 3.89, 0.0, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24021, "ハツネ", 1, 2, 0.0, 213, 113401, "2020/07/31 12:00:00", 24, 13.49, 0.0, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24022, "カヤ", 1, 2, 0.0, 311, 106501, "2020/07/31 12:00:00", 24, 3.17, 0.0, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24023, "カヤ", 1, 2, 0.0, 312, 106501, "2020/07/31 12:00:00", 24, 4.42, 0.0, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24024, "カヤ", 6, 1, 0.0, 313, 106501, "2020/07/31 12:00:00", 24, 2.89, 0.0, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24025, "アヤネ", 4, 3, 0.0, 421, 102301, "2020/07/31 12:00:00", 24, 3.71, 0.0, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24026, "アサヒ", 2, 1, 0.0, 721, 192201, "2020/07/31 12:00:00", 24, 5.1, 0.0, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24027, "部員３", 1, 3, 0.0, 821, 192301, "2020/07/31 12:00:00", 24, 4.34, 0.0, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24028, "", 1, 1, 0.0, 521, 192501, "2020/07/31 12:00:00", 24, 0.0, 0.0, "いい勝負だったよ\nまたやろうね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24029, "ミサト", 1, 2, -360.0, 101, 113501, "2020/07/31 12:00:00", 24, 5.62, 0.0, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24030, "ミサト", 1, 2, -360.0, 102, 113501, "2020/07/31 12:00:00", 24, 9.58, 0.0, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24031, "ミサト", 2, 2, -360.0, 103, 113501, "2020/07/31 12:00:00", 24, 0.0, 0.0, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24032, "ミサト", 2, 1, -360.0, 104, 113501, "2020/07/31 12:00:00", 24, 9.13, 0.0, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！");
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("2030/12/17 14:59:59", 10046, 24033, "ミサト", 1, 2, -360.0, 105, 113501, "2020/07/31 12:00:00", 24, 8.27, 0.0, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！");
